app.post('/login', (req, res) => {
  const { username, password, client_id, redirect_uri, state } = req.body;

  const user = users[username];
  if (!user || user.password !== password) {
    return res.status(401).json({ error: 'Invalid username or password' });
  }

  const client = clients[client_id];
  if (!client) {
    return res.status(400).json({ error: 'Invalid client_id' });
  }

  if (!client.redirect_uris.includes(redirect_uri)) {
    return res.status(400).json({ error: 'Invalid redirect_uri' });
  }

  const authCode = generateRandomString();
  authorizationCodes.set(authCode, {
    client_id,
    redirect_uri,
    username,
    expires_at: Date.now() + 600000
  });

  setTimeout(() => {
    authorizationCodes.delete(authCode);
  }, 600000);

  const redirectUrl = new URL(redirect_uri);
  redirectUrl.searchParams.append('code', authCode);
  if (state) {
    redirectUrl.searchParams.append('state', state);
  }

  res.json({ redirect_url: redirectUrl.toString() });
});

app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret } = req.body;

  if (grant_type !== 'authorization_code') {
    return res.status(400).json({ error: 'unsupported_grant_type' });
  }

  if (!code || !redirect_uri || !client_id || !client_secret) {
    return res.status(400).json({ error: 'invalid_request' });
  }

  const client = clients[client_id];
  if (!client || client.client_secret !== client_secret) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  const authCodeData = authorizationCodes.get(code);
  if (!authCodeData) {
    return res.status(400).json({ error: 'invalid_grant' });
  }

  if (authCodeData.client_id !== client_id) {
    return res.status(400).json({ error: 'invalid_grant' });
  }

  if (authCodeData.redirect_uri !== redirect_uri) {
    return res.status(400).json({ error: 'invalid_grant' });
  }

  if (Date.now() > authCodeData.expires_at) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant' });
  }

  authorizationCodes.delete(code);

  const accessToken = generateRandomString();
  const refreshToken = generateRandomString();

  accessTokens.set(accessToken, {
    client_id,
    username: authCodeData.username,
    expires_at: Date.now() + 3600000
  });

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600,
    refresh_token: refreshToken
  });
});

app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token' });
  }

  const token = authHeader.substring(7);
  const tokenData = accessTokens.get(token);

  if (!tokenData) {
    return res.status(401).json({ error: 'invalid_token' });
  }

  if (Date.now() > tokenData.expires_at) {
    accessTokens.delete(token);
    return res.status(401).json({ error: 'token_expired' });
  }

  res.json({
    sub: tokenData.username,
    username: tokenData.username
  });
});

